using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 changed the discriminator property from "Discriminator" to "$type".
            // Preserve the old name so existing 500K documents remain readable and
            // direct SQL queries that reference c.Discriminator keep working.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed the id format from "EntityType|KeyValue" to just "KeyValue".
            // Preserve the old format so existing documents are still addressable.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();
        });
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // EF Core 9 removed synchronous Cosmos APIs (ToList, First, Single, etc.).
        // All queries must now use async equivalents (ToListAsync, FirstAsync, etc.).
    }
}

